+
+function formatStatusBadge(
+  status: string | undefined,
+  label: string,
+  color: (value: string) => string
+): string {
+  switch (status) {
+    case 'success':
+      return colors.success('✔');
+    case 'failure':
+      return colors.failure('✗ failure');
+    case 'building':
+      return colors.warning('⧗ building');
+    case 'watching':
+      return colors.accent('◉ watching');
+    default:
+      return color(label);
+  }
